export const prototypeHtml = "<div class=\"toast\" id=\"toast\"></div>\n<div class=\"kg-tooltip\" id=\"kgTooltip\">\n  <div class=\"kg-tooltip-title\" id=\"kgTooltipTitle\"></div>\n  <div class=\"kg-tooltip-body\" id=\"kgTooltipBody\"></div>\n</div>\n\n<!-- Reject Modal -->\n<div class=\"modal\" id=\"rejectModal\">\n  <div class=\"modal-box\">\n    <div style=\"display:flex;justify-content:space-between;align-items:center\"><div class=\"modal-title\">Reject with feedback</div><button class=\"btn\" onclick=\"closeReject()\" style=\"background:var(--surface2);border:1px solid var(--border)\">×</button></div>\n    <div class=\"label\" style=\"margin-top:16px\">Select issues</div>\n    <label class=\"issue\"><input type=\"checkbox\"><div><strong>Too obvious</strong><span>The answer is immediately clear without reasoning.</span></div></label>\n    <label class=\"issue\"><input type=\"checkbox\"><div><strong>Distractor too weak</strong><span>One or more alternatives are easy to eliminate.</span></div></label>\n    <label class=\"issue\"><input type=\"checkbox\"><div><strong>Missing key information</strong><span>The case lacks information needed for review.</span></div></label>\n    <label class=\"issue\"><input type=\"checkbox\"><div><strong>Unclear explanation</strong><span>The reasoning path is hard to follow.</span></div></label>\n    <div class=\"modal-footer\"><button class=\"btn\" onclick=\"closeReject()\" style=\"background:var(--surface2);border:1px solid var(--border)\">Cancel</button><button class=\"btn reject\" onclick=\"submitReject()\">Submit feedback</button></div>\n  </div>\n</div>\n\n<!-- Regenerate Modal -->\n<div class=\"modal\" id=\"regenerateModal\">\n  <div class=\"modal-box\">\n    <div style=\"display:flex;justify-content:space-between;align-items:center\"><div class=\"modal-title\">Regenerate this question</div><button class=\"btn\" onclick=\"closeRegenerate()\" style=\"background:var(--surface2);border:1px solid var(--border)\">×</button></div>\n    <div class=\"study-note\" style=\"margin-top:14px\">This task intentionally starts with a flawed question. Select why it should be regenerated. After regeneration, all three support modes remain available: Text only, KG only, and KG + enriched hover text.</div>\n    <div class=\"label\" style=\"margin-top:16px\">Why should this question be regenerated?</div>\n    <label class=\"issue\"><input type=\"checkbox\" value=\"too_obvious\"><div><strong>The correct answer is too obvious</strong><span>The vignette gives away the diagnosis too directly.</span></div></label>\n    <label class=\"issue\"><input type=\"checkbox\" value=\"too_much_evidence\"><div><strong>Too much evidence</strong><span>Too many classic clues point to the same diagnosis.</span></div></label>\n    <label class=\"issue\"><input type=\"checkbox\" value=\"answer_named\"><div><strong>Correct answer is almost named</strong><span>The case uses wording that nearly names the answer.</span></div></label>\n    <label class=\"issue\"><input type=\"checkbox\" value=\"weak_distractors\"><div><strong>Distractors are too easy to eliminate</strong><span>The alternatives are excluded by obvious negative findings.</span></div></label>\n    <label class=\"issue\"><input type=\"checkbox\" value=\"too_easy\"><div><strong>Too easy for the target learner</strong><span>The item tests keyword recognition rather than clinical reasoning.</span></div></label>\n    <div class=\"study-note\" id=\"selectedClueSummary\" style=\"margin-top:14px\"></div>\n    <div class=\"modal-footer\"><button class=\"btn\" onclick=\"closeRegenerate()\" style=\"background:var(--surface2);border:1px solid var(--border)\">Cancel</button><button class=\"btn accept\" onclick=\"applyRegenerate()\">Generate revised version</button></div>\n  </div>\n</div>\n\n<!-- Custom Confirmation Modal -->\n<div class=\"modal\" id=\"customConfirmModal\">\n  <div class=\"modal-box\">\n    <div style=\"display:flex;justify-content:space-between;align-items:center;gap:12px\">\n      <div class=\"modal-title\" id=\"customConfirmTitle\">Confirm action</div>\n      <button class=\"btn\" onclick=\"closeCustomConfirm()\" style=\"background:var(--surface2);border:1px solid var(--border)\">×</button>\n    </div>\n    <div class=\"custom-confirm-body\" id=\"customConfirmBody\"></div>\n    <div class=\"custom-confirm-list\" id=\"customConfirmList\" style=\"display:none\"></div>\n    <div class=\"modal-footer\">\n      <button class=\"btn\" onclick=\"closeCustomConfirm()\" style=\"background:var(--surface2);border:1px solid var(--border)\">Cancel</button>\n      <button class=\"btn reject\" id=\"customConfirmPrimaryBtn\">Confirm</button>\n    </div>\n  </div>\n</div>\n\n<!-- Bank Modal -->\n<div class=\"modal\" id=\"bankModal\">\n  <div class=\"modal-box bank-modal-box\">\n    <div style=\"display:flex;justify-content:space-between;align-items:center;gap:12px\">\n      <div class=\"modal-title\">Accepted question bank</div>\n      <button class=\"btn\" onclick=\"closeBank()\" style=\"background:var(--surface2);border:1px solid var(--border)\">×</button>\n    </div>\n    <div id=\"bankList\" style=\"margin-top:16px\"></div>\n    <div class=\"modal-footer\"><button class=\"btn\" onclick=\"closeBank()\" style=\"background:var(--surface2);border:1px solid var(--border)\">Close</button></div>\n  </div>\n</div>\n\n<!-- Question Picker Modal -->\n<div class=\"picker-modal\" id=\"pickerModal\">\n  <div class=\"picker-box\">\n    <div class=\"picker-head\"><strong>Select a question</strong><button class=\"btn\" onclick=\"closePicker()\" style=\"background:var(--surface2);border:1px solid var(--border)\">×</button></div>\n    <input class=\"picker-search\" id=\"pickerSearch\" placeholder=\"Search a question\" oninput=\"filterPicker(this.value)\"/>\n    <div class=\"picker-list\" id=\"pickerList\"></div>\n    <div class=\"picker-footer\">\n      <button class=\"btn\" onclick=\"closePicker()\" style=\"background:var(--surface2);border:1px solid var(--border)\">Cancel</button>\n      <button class=\"btn accept\" id=\"pickerConfirmBtn\" onclick=\"confirmPicker()\" disabled style=\"opacity:.45\">Confirm</button>\n    </div>\n  </div>\n</div>\n\n<!-- ══ SETUP PAGE ══ -->\n<div id=\"setupPage\">\n  <div class=\"setup-logo\">Med<span>MCQ</span></div>\n  <div class=\"setup-sub\">User study prototype · Question Setup</div>\n  <div class=\"setup-card\">\n    <div class=\"setup-title\">Question Setup</div>\n    <div class=\"setup-desc\">Configure your medical education question parameters</div>\n    <div class=\"field\">\n      <div class=\"field-label\">Domain</div>\n      <select class=\"select-box\" id=\"setupDomain\"><option value=\"pediatrics\" selected>Pediatrics</option></select>\n    </div>\n    <div class=\"field\">\n      <div class=\"field-label\">Topic</div>\n      <select class=\"select-box\" id=\"setupTopic\"><option value=\"respiratory_system\" selected>Respiratory System</option></select>\n    </div>\n    <div class=\"field\">\n      <div class=\"field-label\">Difficulty Level</div>\n      <div class=\"diff-row\">\n        <button class=\"diff-btn active\" id=\"diff-easy\" onclick=\"selectDiff('easy')\"><strong>Easy</strong><span>Basic concepts</span></button>\n        <button class=\"diff-btn\" id=\"diff-medium\" onclick=\"selectDiff('medium')\"><strong>Medium</strong><span>Clinical reasoning</span></button>\n        <button class=\"diff-btn\" id=\"diff-hard\" onclick=\"selectDiff('hard')\"><strong>Hard</strong><span>Complex cases</span></button>\n      </div>\n    </div>\n    <div class=\"divider\"></div>\n    <div class=\"field\">\n      <div class=\"field-label\">Start from</div>\n      <div class=\"start-mode\">\n        <button class=\"mode-btn active\" id=\"mode-new\" onclick=\"selectMode('new')\">\n          <span class=\"mode-icon\">✦</span>\n          <div><strong>Generate a new question</strong><span>AI generates fresh MCQ from KG</span></div>\n        </button>\n        <button class=\"mode-btn\" id=\"mode-existing\" onclick=\"selectMode('existing')\">\n          <span class=\"mode-icon\">📂</span>\n          <div><strong>Modify an existing question</strong><span>Edit from question bank</span></div>\n        </button>\n      </div>\n    </div>\n    <button class=\"go-btn\" onclick=\"startStudy()\">Generate question</button>\n  </div>\n</div>\n\n<!-- ══ APP PAGE ══ -->\n<div id=\"appPage\">\n  <!-- TOP NAV -->\n  <nav class=\"topnav\">\n    <div class=\"nav-logo\">Med<span>MCQ</span></div>\n    <div class=\"nav-divider\"></div>\n    <div class=\"task-tabs\">\n      <button class=\"nav-tab active\" id=\"navTab1\" onclick=\"loadTask(1)\">Task 1 <span class=\"pill text\">Text only</span></button>\n      <button class=\"nav-tab\" id=\"navTab2\" onclick=\"loadTask(2)\">Task 2 <span class=\"pill kg\">KG ± hover</span></button>\n      <button class=\"nav-tab\" id=\"navTab3\" onclick=\"loadTask(3)\">Task 3 <span class=\"pill both\">Regenerate</span></button>\n    </div>\n    <div class=\"nav-meta\">\n      <span class=\"meta-chip\" id=\"navChip\">Explanation: Text only</span>\n      <button class=\"bank-btn\" onclick=\"openBank()\">Question bank <span class=\"bank-count\" id=\"navBankCount\">0</span></button>\n      <button class=\"back-nav-btn\" onclick=\"goSetup()\">← Setup</button>\n    </div>\n  </nav>\n\n  <!-- MAIN BODY -->\n  <div class=\"app-body\" id=\"vignetteCard\">\n    <!-- LEFT COLUMN -->\n    <div class=\"left-col\">\n      <!-- Vignette card -->\n      <div class=\"lcard\">\n        <div class=\"vignette-section\" id=\"vignetteSection\">\n          <div class=\"card-label\">Clinical vignette</div>\n          <div id=\"sourceTag\"></div>\n          <div class=\"vignette\" id=\"vignette\"></div>\n        </div>\n      </div>\n\n      <!-- Question card -->\n      <div class=\"lcard\">\n        <div class=\"question-section\">\n          <div class=\"card-label\">Question</div>\n          <div class=\"stem\" id=\"stem\"></div>\n          <div id=\"options\"></div>\n          <div class=\"difficulty\">\n            <span style=\"font-size:12px;color:var(--text2)\">Difficulty</span>\n            <span class=\"diff-chip easy\" id=\"diffChip\">Easy</span>\n          </div>\n        </div>\n        <!-- Actions -->\n        <div class=\"actions-section\" id=\"actionsSection\"></div>\n        <!-- Edit Panel -->\n          <div class=\"edit-section hidden\" id=\"editSection\">\n          <div class=\"card-label\">Revision notes &amp; edits</div>\n          <div class=\"label\">Question stem</div>\n          <textarea class=\"textarea\" id=\"editStem\"></textarea>\n          <div class=\"label\">Clinical vignette</div>\n          <textarea class=\"textarea\" id=\"editVignette\" style=\"min-height:110px\"></textarea>\n          <div class=\"edit-grid\">\n            <div><div class=\"label\">Option A</div><input class=\"edit-input\" id=\"editA\"></div>\n            <div><div class=\"label\">Option B</div><input class=\"edit-input\" id=\"editB\"></div>\n            <div><div class=\"label\">Option C</div><input class=\"edit-input\" id=\"editC\"></div>\n            <div><div class=\"label\">Option D</div><input class=\"edit-input\" id=\"editD\"></div>\n            <div><div class=\"label\">Option E</div><input class=\"edit-input\" id=\"editE\"></div>\n          </div>\n          <div class=\"label\">Correct answer</div>\n          <select class=\"edit-input\" id=\"editCorrect\"><option>A</option><option>B</option><option>C</option><option>D</option><option>E</option></select>\n          <div style=\"margin-top:12px;display:flex;gap:10px\">\n            <button class=\"btn accept\" onclick=\"saveEdits()\">Save revision</button>\n            <button class=\"btn edit-btn\" onclick=\"toggleEdit(false)\">Cancel</button>\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <!-- RIGHT COLUMN: KG + Text explanation -->\n    <div class=\"right-col\">\n      <div class=\"kg-panel\">\n        <div class=\"kg-panel-head\">\n          <div class=\"kg-panel-title\" id=\"kgPanelTitle\">Knowledge graph · Reasoning support</div>\n          <div style=\"display:flex;align-items:center;gap:12px;flex-wrap:wrap;justify-content:flex-end\">\n            <div class=\"kg-hint\" id=\"kgHint\">Click nodes to reveal nearby knowledge</div>\n            <button class=\"explain-btn\" id=\"kgHeaderExplainBtn\" onclick=\"toggleHeaderExplain()\" style=\"display:none\">Hide explanation</button>\n          </div>\n        </div>\n        <div class=\"task3-support-switch\" id=\"task3SupportSwitch\">\n          <div class=\"task3-support-left\">\n            <div class=\"task3-support-title\">Task 3 support mode</div>\n            <div class=\"task3-support-sub\" id=\"task3SupportSub\">Turn on clue edit mode, then use the small × on clue nodes to confirm whether they should be removed or weakened before regeneration.</div>\n          </div>\n          <div class=\"mode-toggle-wrap\">\n            <button class=\"support-mode-btn\" id=\"supportModeText\" onclick=\"setTask3SupportMode('text')\">Text</button>\n            <button class=\"support-mode-btn\" id=\"supportModeKg\" onclick=\"setTask3SupportMode('kg')\">KG</button>\n          </div>\n        </div>\n        <div id=\"kgBoard\" class=\"reasoning-board\"></div>\n        <div class=\"provenance-note\" id=\"kgProvenanceNote\" style=\"display:none\">\n          <span class=\"prov-key\"><span class=\"prov-dot case\"></span>CASE: original vignette evidence</span>\n          <span class=\"prov-key\"><span class=\"prov-dot casekg\"></span>KG node: vignette phrase already matches KG concept</span>\n          <span class=\"prov-key\"><span class=\"prov-dot kg\"></span>KG: mapped/base knowledge node</span>\n          <span class=\"prov-key llm-prov\"><span class=\"prov-dot llm\"></span>LLM: hover text explains the edge</span>\n        </div>\n        <div class=\"right-text-panel delayed-panel\" id=\"kgTextPanel\">\n          <div class=\"right-text-panel-head\">\n            <div class=\"right-text-panel-title\">Text explanation</div>\n          </div>\n          <div class=\"right-text-body open\">\n            <div class=\"why\" id=\"kgTextWhy\"></div>\n            <div class=\"distractor-grid\" id=\"kgTextDistractors\"></div>\n          </div>\n        </div>\n        <div class=\"path-text\" id=\"pathText\"></div>\n        <div class=\"exclude-wrap\" id=\"kgExcludeWrap\" style=\"display:none\">\n          <div class=\"exclude-section-title\" id=\"miniGraphTitle\">Distractor mini graphs</div>\n          <div class=\"exclude-grid\" id=\"kgExcludeCards\"></div>\n          <div class=\"mini-graph-footer-hint\" id=\"miniGraphHint\">Hover evidence nodes to highlight the vignette.</div>\n        </div>\n        <!-- Text explanation panel (Task 1 only, in right col) -->\n        <div class=\"right-text-panel\" id=\"rightTextPanel\" style=\"display:none\">\n          <div class=\"right-text-panel-head\">\n            <div class=\"right-text-panel-title\">Reasoning support — Text explanation</div>\n            <button class=\"explain-btn\" id=\"explainBtn\" onclick=\"toggleTextExplain()\">Hide explanation</button>\n          </div>\n          <div class=\"right-text-body\" id=\"rightTextBody\">\n            <div class=\"why\" id=\"textWhy\"></div>\n            <div class=\"distractor-grid\" id=\"textDistractors\"></div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n</div>";
